const body = $input.first().json.body || $input.first().json;

const query = body.query || body.q || '';
const maxResults = parseInt(body.maxResults || body.limit || 10, 10);

if (!query) throw new Error('Missing required field: query. Use Gmail search syntax e.g. "from:john subject:invoice"');
if (maxResults < 1 || maxResults > 100) throw new Error('maxResults must be between 1 and 100');

return [{ json: { query, maxResults } }];

// Aggregate all Gmail search results into a single response
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { emails: [], count: 0 } }];
}

const emails = items.map(item => {
  const msg = item.json;
  const headers = msg.payload?.headers || [];
  const getHeader = (name) =>
    headers.find(h => h.name.toLowerCase() === name.toLowerCase())?.value || '';

  return {
    id: msg.id || '',
    threadId: msg.threadId || '',
    subject: getHeader('Subject') || msg.subject || '',
    from: getHeader('From') || msg.from || '',
    to: getHeader('To') || msg.to || '',
    date: getHeader('Date') || msg.date || '',
    snippet: msg.snippet || '',
    labelIds: msg.labelIds || [],
    isUnread: (msg.labelIds || []).includes('UNREAD')
  };
});

return [{ json: { emails, count: emails.length } }];
